window.__QUIZ_DATA__=[{"id":"objective>Mathematics>2017>1","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Express 0.0000407, correct to 2 significant figures.","images":[],"options":{"A":"0.0","B":"0.00004","C":"0.000041","D":"0.0000407"},"answer":"C","explanation":"0.0000407 ----- {Given}  Since the 3rd significant figure is greater than 5, we will round it up to 1 and add it to the 2nd significant figure.  Hence: 0.0000407 = 0.000041 to 2.s.f","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2017>2","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : VARIATION","question":"If x varies inversely as y and y varies directly as z, what is the relationship between x and z?","images":[],"options":{"A":"x \u03b1 z","B":"x \u03b1 1/z","C":"x \u03b1 z2","D":"x \u03b1 1/z2"},"answer":"B","explanation":"x \u03b1 1/y --------- (1)  y \u03b1 z -------- (2)    \u2234 the relationship between x and z is x \u03b1 1/z","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>3","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : FRACTIONS, DECIMALS AND APPROXIMATIONS","question":"Evaluate3 1/4 \u00d7 13/511 1/3 - 5 1/3","images":[],"options":{"A":"1415","B":"1315","C":"45","D":"1115"},"answer":"B","explanation":"3 1/4 \u00d7 1 3/511 1/3 - 5 1/3  Convert all mixed fractions to improper fractions  13/4 \u00d7 8/5 (NUMERATOR)  34/3 - 16/3 (DENOMINATOR)  Treat the numerator and denominator separately  134\u00d785=13\u00d725=265  343-163=183=6  343-163=183=6  =265\u00d716=2630=1315","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>4","subject":"Mathematics","year":"2017","type":"Objective","topic":"ALGEBRAIC PROCESSES : BINARY OPERATIONS","question":"Fig. 1 and Fig. 2 are the addition and multiplication tables respectively in modulo 5. Use these tables to solve the equation (n \u2297 4) \u2295 3 = 0 (mod 5)","images":["data:image/jpeg;base64,"],"options":{"A":"1","B":"2","C":"3","D":"4"},"answer":"C","explanation":"(n \u2297 4) + 3 = 0 (mod 5)  4n + 3 = 0 (mod 5)  4n = -3 + 5 (mod 5)  4n = 2 + 5 (mod 5)  4 n = 7 + 5 (mod 5)  4n = 12  n=124=3(mod5)","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>5","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"The ages of Tunde and Ola are in the ratio 1:2. If the ratio of Ola's age to Musa's age is 4:5, what is the ratio of Tunde's age to Musa's age?","images":[],"options":{"A":"1:4","B":"1:5","C":"2:5","D":"5:2"},"answer":"C","explanation":"Let T, k and M represent Tunde's, Ola's and Musa's ages respectively.  TK=12-----------(1)  KM=45-----------(2)  TM=?  N.B: TM=TK\u00d7KM  =12\u00d745=410=25","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>6","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : SETS","question":"If M = {x : 3 \u2264 x  I. 8 \u2208M \u2229 N  II. 8 \u2208M \u222a N  III. M \u2229 N = \u2205","images":[],"options":{"A":"III only","B":"I and II only","C":"II and III only","D":"I, II and III"},"answer":"A","explanation":"M = { x : 3 \u2264 x  M = {3, 4, 5, 6, 7}  N = {x:8  N = {9, 10, 11, 12}  M \u2229 N = \u2205  III only is correct.","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>7","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : LOGARITHMS","question":"Given that a = log7 and b = log2, express log 35 in terms of a and b.","images":[],"options":{"A":"a + b + 1","B":"ab - 1","C":"a - b + 1","D":"b - a + 1"},"answer":"C","explanation":"a = log7, b = log2  log32=log702-log2  log 7 \u00d7 10 - log2 = log7 + log10 - log2= a + 1 - b= a - b + 1","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>8","subject":"Mathematics","year":"2017","type":"Objective","topic":"ALGEBRAIC PROCESSES : FORMULATION AND EVALUATION OF ALGEBRAIC PROCESSES","question":"If x = 2/3 and y = -6, evaluate xy - y/x.","images":[],"options":{"A":"0","B":"5","C":"8","D":"9"},"answer":"B","explanation":"x = 2/3 ; y = -6  xy-yx=(23)(-6)--62/3= -4 + 9 = 5","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2017>9","subject":"Mathematics","year":"2017","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR EQUATIONS IN ONE VARIABLE","question":"Solvetheequation:15x+1x=3.","images":[],"options":{"A":"1/5","B":"2/5","C":"3/5","D":"4/5"},"answer":"B","explanation":"15x+1x=31  1+55x=31  6 = 15x  x = 6/15 = 2/5","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2017>10","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : RATIO, PROPORTIONS AND RATES","question":"A sum of N18,100.00 was shared among 5 boys and 4 girls with each boy taking N20.00 more than each girl. Find a boy's share.","images":[],"options":{"A":"N1,820.00","B":"N2,000.00","C":"N2,020.00","D":"N2,040.00"},"answer":"C","explanation":"5B + 4G = \u20a618,100 -------------- (1)  B = \u20a620 + G ------------- (2)  Substitute for B = \u20a620 + G in (1)  5(\u20a620 + G) + 4G = \u20a618,100  \u20a6100 + 5G + 4G = \u20a618,100  9G = \u20a618,000  G = \u20a62,000  B = \u20a62,000 + 20 {from (2)}  B = \u20a62,020","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>11","subject":"Mathematics","year":"2017","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"One factor of 7x2 + 33x - 10 is","images":[],"options":{"A":"7x + 5","B":"x - 2","C":"7x - 2","D":"x - 5"},"answer":"C","explanation":"7x2 + 33x - 10  7x2 + 35x - 2x - 10  7x(x + 5) - 2(x + 5)  (7x - 2)(x + 5)  The factors of 7x2 + 33x - 10 are (7x - 2) and (x + 5). It follows that one of its factor is 7x - 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>12","subject":"Mathematics","year":"2017","type":"Objective","topic":"ALGEBRAIC PROCESSES : LINEAR INEQUALITIES","question":"Solve:-1434(3x-2)12","images":[],"options":{"A":"59x89","B":"-89x79","C":"-89x59","D":"-79x89"},"answer":"A","explanation":"-1434(3x-2)12  -1434(3x-2)---------(1)  34(3x-2)12-----------(2)  \u2192-149x - 64  -149x4-64  549x4  9x > 5  x > 5/9 ------------ *    \u2192 34(3x-2)12  9x-6412  9x412+32  9x421  9x  x   Combine * and   x>59&x89  59x89","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>13","subject":"Mathematics","year":"2017","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify: 3x - (p - x) - (r - p)","images":[],"options":{"A":"2x - r","B":"2x + r","C":"4x - r","D":"2x - 2p - r"},"answer":"C","explanation":"3x - (p - x) - (r - p)  3x - p + x - r + p  3x + x - r  4x - r","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>14","subject":"Mathematics","year":"2017","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"An arc of a circle of radius 7.5cm is 7.5cm long. Find, correct to the nearest degree, the angle which the arc subtends at the centre of the circle. [ Take \u03c0 = 22/7 ]","images":[],"options":{"A":"29\u00b0","B":"57\u00b0","C":"65\u00b0","D":"115\u00b0"},"answer":"B","explanation":"Radius, r = 7.5cm  Length of arc, L = 7.5cm  Angle, \u03b8 = ?    recall,   L=\u03b8360\u00d72\u03c0r  7.5=\u03b8360\u00d7447\u00d77.5  \u03b8=48 \u00d7 7 \u00d7 7.544  \u03b8 = 57.27\u00b0 \u2248 57\u00b0 to the nearest degree..","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>15","subject":"Mathematics","year":"2017","type":"Objective","topic":"MENSURATION : VOLUMES","question":"Water flows out of a pipe at a rate of 40\u03c0cm3 per second into an empty cylindrical container of base radius 4cm. Find the height of water in the container after 4 seconds","images":[],"options":{"A":"10cm","B":"14cm","C":"16cm","D":"20cm"},"answer":"A","explanation":"Rate of flow of water = 40\u03c0cm3s-1    t = 4second   Volume of cylinder = \u03c0r2h  Vc = \u03c0 \u00d7 (4)2 \u00d7 h = 16\u03c0h cm3  Note:   40\u03c0cm3 \u2192 1s  16\u03c0hcm3 \u2192 4s  40\u03c016\u03c0h=14  h = 10cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>16","subject":"Mathematics","year":"2017","type":"Objective","topic":"MENSURATION : VOLUMES","question":"The dimensions of a water tank are 13cm, 10cm and 70cm. If it is half-filled with water, calculate the volume of water in litres.","images":[],"options":{"A":"4.55 litres","B":"7.50 litres","C":"8.10 litres","D":"9.55 litres"},"answer":"A","explanation":"Length = 13cm, Breadth = 10cm, Height = 70cm    Volume of cuboid = L \u00d7 B \u00d7 H  Volume of the cuboidal water tank = 13cm \u00d7 10cm \u00d7 70cm = 91,000cm3  Volumewhenhalf-filled=12\u00d791,000cm3 = 45,500cm3  N.B: 1 litre = 1000cm3  x = 45,500cm3  1x=100045,500  x = 4.55litres","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>17","subject":"Mathematics","year":"2017","type":"Objective","topic":"MENSURATION : VOLUMES","question":"If the total surface area of a solid hemisphere is equal to its volume, find the radius.","images":[],"options":{"A":"3.0cm","B":"4.5cm","C":"5.0cm","D":"9.0cm"},"answer":"B","explanation":"N.B: Total surface area of a hemisphere = 3\u03c0r2  Volume of hemisphere = 2/3 \u03c0r3  3\u03c0r2=23\u03c0r(3)  3=23r  9 = 2r  r = 9/2 = 4.5cm","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>18","subject":"Mathematics","year":"2017","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Which of the following is true about parallelograms?","images":[],"options":{"A":"Opposite angles are supplementary","B":"Opposite angles are complementary","C":"Opposite angles are equal","D":"Opposite angles are reflex angles"},"answer":"C","explanation":"In a parallelogram, opposite angles are equal and adjacent angles are supplementary","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2017>19","subject":"Mathematics","year":"2017","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"The diagram shows a circle centre O, If \u2220STR = 29\u00b0 and \u2220RST = 46\u00b0. Calculate the value of \u2220STO.","images":["data:image/png;base64,"],"options":{"A":"12\u00b0","B":"15\u00b0","C":"29\u00b0","D":"34\u00b0"},"answer":"B","explanation":"It should be noted that:  \u2220TOR = 2 \u00d7 \u2220TSR (angle at the centre is twice that at the circumference)  \u2220 TOR = 2 \u00d7 46\u00b0 = 92\u00b0  In \u0394TOR  \u2220T = \u2220R (Base angle of isosceles)  \u2220O + \u2220T + \u2220R = 180\u00b0 (sum of *angles*s in a \u0394)  \u2220O + 2\u2220T = 180\u00b0  92\u00b0 + 2\u2220T = 180\u00b0  \u2220T = 44\u00b0  N.B: 44\u00b0 = \u2220STO + \u2220STR  \u222044\u00b0 = \u2220STO + 29\u00b0  \u2220STO = 15\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>20","subject":"Mathematics","year":"2017","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"In the diagram, XY is a straight line, \u2220POX = \u2220POQ and \u2220ROY = \u2220QOR. Find the value of \u2220POQ + \u2220ROY.","images":["data:image/png;base64,"],"options":{"A":"60\u00b0","B":"90\u00b0","C":"100\u00b0","D":"120\u00b0"},"answer":"B","explanation":"\u2220POX = \u2220POQ = x ---------------- *  \u2220ROY = \u2220QOR = y --------------- **  The value of \u2220POQ + \u2220ROY is unknown   x + x + y + y = 180\u00b0 (sum of \u2220s on a straight line)  2x + 2y = 180\u00b0  x + y = 90\u00b0  \u2220POQ + \u2220ROY = x + y = 90\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>21","subject":"Mathematics","year":"2017","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"The diagram shows a circle centre O.  If \u2220ZYW = 33\u00b0, find \u2220ZWX.","images":["data:image/png;base64,"],"options":{"A":"33\u00b0","B":"57\u00b0","C":"90\u00b0","D":"100\u00b0"},"answer":"B","explanation":"\u2220ZYW = \u2220ZXW = 33\u00b0 (angles in the same segment)  In \u0394ZWX  \u2220ZXW = 33\u00b0 --------------- *  \u2220WZX = 90\u00b0 (angle in a semi-circle)  \u2220ZWX = unknown  33\u00b0 + 90\u00b0 + \u2220ZWX = 180\u00b0 (sum of \u2220s in a triangle)  123\u00b0 + \u2220ZWX = 180\u00b0  \u2220ZWX = 57\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>22","subject":"Mathematics","year":"2017","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"In the diagram, PQ and PS are tangents to the circle centre O. If \u2220PSQ = m, \u2220SPQ = n and \u2220SQR = 33\u00b0, find the value of (m + n).","images":["data:image/png;base64,"],"options":{"A":"103\u00b0","B":"123\u00b0","C":"133\u00b0","D":"143\u00b0"},"answer":"B","explanation":"N.B: The angle between the diameter and the tangent to the circle = 90\u00b0  33\u00b0 + \u2220SQP = 90\u00b0  \u2220SQP = 57\u00b0  In \u0394SQP  \u2220SQP + m + n = 180\u00b0 (sum of angles in a triangle)  57\u00b0 + m + n = 180\u00b0  m + n = 180\u00b0 - 57\u00b0  m + n = 123\u00b0","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>23","subject":"Mathematics","year":"2017","type":"Objective","topic":"COORDINATE GEOMETRY OF STRAIGHT LINES : CONCEPT OF THE X-Y PLANE AND COORDINATES OF POINTS ON THE X-Y PLANE","question":"Calculate the gradient (slope) of the line joining points (-1, 1) and (2, -2).","images":[],"options":{"A":"-1","B":"-1/2","C":"1/2","D":"1"},"answer":"A","explanation":"Recall: The slope of two points, A(x1, y1) and B(x2, y2) is given as   m=y2-y1x2-x1  The slope in this case  m=-2-12--1=-33=-1","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2017>24","subject":"Mathematics","year":"2017","type":"Objective","topic":"COORDINATE GEOMETRY OF STRAIGHT LINES : CONCEPT OF THE X-Y PLANE AND COORDINATES OF POINTS ON THE X-Y PLANE","question":"If P(2, 3) and Q(2, 5) are points on a graph, calculate the length PQ.","images":[],"options":{"A":"6 units","B":"5 units","C":"4 units","D":"2 units"},"answer":"D","explanation":"Recall: Given two points A(x1, y1) and B(x2, y2)  AB = &radic;(x2 - x1)2 + (y2 - y1)2&nbsp;  In this case,  PQ = &radic;(5 - 3)2 + (2 - 2)2&nbsp;  PQ = &radic;22&nbsp; = 2 units","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2017>25","subject":"Mathematics","year":"2017","type":"Objective","topic":"TRIGONOMETRY : BEARINGS","question":"A bearing of 320\u00b0 expressed as a compass bearing is","images":[],"options":{"A":"N50\u00b0W","B":"N40\u00b0W","C":"N50\u00b0E","D":"N40\u00b0E"},"answer":"B","explanation":"320\u00b0 = N40\u00b0W (40\u00b0 West of North)  \u2234 the bearing of 320\u00b0 expressed as a compass bearing is N40\u00b0W.","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2017>26","subject":"Mathematics","year":"2017","type":"Objective","topic":"TRIGONOMETRY : SINE, COSINE AND TANGENT OF AN ANGLE","question":"Giventhatcos30\u00b0=sin60\u00b0=&radic;3&nbsp;2andsin30\u00b0=cos60\u00b0=12,evaluatetan60\u00b0-(-1)1-tan30\u00b0","images":[],"options":{"A":"&radic;3 - 2&nbsp;","B":"2 - &radic;3&nbsp;","C":"&radic;3&nbsp;","D":"2&radic;3&nbsp;+3"},"answer":"D","explanation":"tan60\u00b0 = &radic;3&nbsp;  tan30\u00b0=1&radic;3&nbsp;  tan60\u00b0-(-1)1 - tan30=&radic;3&nbsp; + 11 - 1/&radic;3&nbsp;  &radic;3&nbsp;(&radic;3&nbsp;+1)&radic;3&nbsp;-1  Rationalize  (3+&radic;3&nbsp;)(&radic;3&nbsp;+1)(&radic;3&nbsp;-1)(&radic;3&nbsp;+1)=3&radic;3&nbsp;+3+3+&radic;3&nbsp;3-1  =4&radic;3&nbsp;+62=2&radic;3&nbsp;+3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>27","subject":"Mathematics","year":"2017","type":"Objective","topic":"TRIGONOMETRY : ANGLES OF ELEVATION AND DEPRESSION","question":"A stationary boat is observed from a height of 100m. If the horizontal distance between the observer and the boat is 80m, calculate, correct to two decimal places, the angle of depression of the boat from the point of observation.","images":[],"options":{"A":"36.87\u00b0","B":"39.70\u00b0","C":"51.34\u00b0","D":"53.13\u00b0"},"answer":"C","explanation":"Diagrammatically, we have:    tan\u03b8=100m80m  tan\u03b8 = 5/4  \u03b8 = tan-1( 5/4 )  \u03b8 = 51.34\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>28","subject":"Mathematics","year":"2017","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The average age of a group 25 girls is 10 years. If one girl, aged 12 years and 4 months joins the group, find, correct to one decimal place, the new average age of the group.","images":[],"options":{"A":"10.1 years","B":"9.3 years","C":"8.7 years","D":"8.3 years"},"answer":"A","explanation":"Recall:Mean(x\u0305)=\u2211xn  x\u03051 = 10 years   n1 = 25girls  n2 = (25 + 1)girls = 26girls   \u2211x1 = x\u03051n1 = (10)(25) = 250years   \u2211x2 = x\u03052n2 = \u2211x1 + 12 years, 4 months   = \u2211x1 + 12.33years  \u2211x2 = (250 + 12.33) years   = 262.33 years   x\u03052=\u2211x2n2=262.3326=10.1years","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2017>29","subject":"Mathematics","year":"2017","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"The bar chart shows the statistics of the number of passes and failures in an examination in a school from 2001 to 2004. What is the ratio of the total number of passes to the total number of failures?","images":["data:image/png;base64,"],"options":{"A":"60:13","B":"10:3","C":"5:1","D":"40:13"},"answer":"A","explanation":"From the chart  * The total number of passs = 285  * The total number of failure = 65  Ratioof no of passesno of failure=28565=6013","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>30","subject":"Mathematics","year":"2017","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Marks012345Frequency741812811  The table gives the distribution of marks obtained by a number of pupils in a class test. Use this information to answer this question.    Find the median of the distribution.","images":[],"options":{"A":"4","B":"3","C":"2","D":"1"},"answer":"B","explanation":"Sum of the total frequency = 7 + 4 + 18 + 12 + 8 + 11= 60  SincethetotalfrequencyisEVEN,themiddlenumber=nth/2 + (n+2/2 2  =30th +  31th2  =3+32=62= 3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>31","subject":"Mathematics","year":"2017","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Marks012345Frequency741812811  The table gives the distribution of marks obtained by a number of pupils in a class test. Use this information to answer this question.  Find the first quartile","images":[],"options":{"A":"1.0","B":"1.5","C":"2.0","D":"2.5"},"answer":"C","explanation":"FirstQuartile=Q1=14\u00d7TotalFrequency  =14\u00d760=15thvalues= 2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>32","subject":"Mathematics","year":"2017","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"In a class of 45 students, 28 offers chemistry and 25 offer Biology. If each student offers at least one of the two subjects, calculate the probability that a student selected at random from the class offers Chemistry only.","images":[],"options":{"A":"2/9","B":"4/9","C":"5/9","D":"7/9"},"answer":"B","explanation":"Probabilitythatastudentselectedatrandomfromtheclassofferschemistryonly=Number of Students offering ONLY chemistryTotal number of students  45 = 28 + 25 - x  x = 53 - 45  x = 8  8 students offer both chemistry and biology.  (28 - 8) students offer only chemistry= 20 students   theprobability(chemistryonly)=2045=49","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>33","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : NUMBER BASES","question":"In what number base was the addition 1 + nn = 100, where n > 0, done?","images":[],"options":{"A":"n - 1","B":"n","C":"n + 1","D":"n + 2"},"answer":"A","explanation":"The base in  which  the addition was done is: n\u22121.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>34","subject":"Mathematics","year":"2017","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplify: &radic;2&nbsp;(&radic;6&nbsp; + 2&radic;2&nbsp;) - 2&radic;3&nbsp;","images":[],"options":{"A":"4","B":"&radic;3&nbsp; + 4","C":"4&radic;2&nbsp;","D":"4&radic;3&nbsp; + 4"},"answer":"A","explanation":"&radic;2&nbsp;(&radic;6&nbsp; + 2&radic;2&nbsp;) - 2&radic;3&nbsp;  &radic;12&nbsp; + 2(2) - 2&radic;3&nbsp;  2&radic;3&nbsp; + 4 - 2&radic;3&nbsp;= 4","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>35","subject":"Mathematics","year":"2017","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Three exterior angles of a polygon are 30\u00b0, 40\u00b0 and 60\u00b0. If the remaining exterior angles are 46\u00b0 each, name the polygon.","images":[],"options":{"A":"Decagon","B":"Nonagon","C":"Octagon","D":"Hexagon"},"answer":"C","explanation":"If the three exterior angles are: 30\u00b0, 40\u00b0 and 60\u00b0, it follows that the interior angles are:  150\u00b0, 140\u00b0 and 120\u00b0 respectively.  N.B: Interior angle + Exterior angle = 180\u00b0  The sum of the remaining interior angle = 134x, where x = number of the remaining sides  134x + 150 + 140 + 120 = 180(n - 2)  134x + 410 = 180(x + 1)  134x + 410 = 180x + 180  230 = 46x  x = 5  The total number of sides = 5 + 3 = 8  The polygon is an octagon.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>36","subject":"Mathematics","year":"2017","type":"Objective","topic":"PLANE GEOMETRY : ANGLES AND INTERCEPTS ON PARALLEL LINES","question":"In the diagram, NQ//TS, \u2220RTS = 50\u00b0 and \u2220PRT = 100\u00b0. Find the value of \u2220NPR.","images":["data:image/png;base64,"],"options":{"A":"110\u00b0","B":"130\u00b0","C":"140\u00b0","D":"150\u00b0"},"answer":"B","explanation":"100\u00b0 + \u2220PRQ = 180\u00b0 (sum of angles on a straight line)  \u2220PRQ = 80\u00b0  TS//PQ  \u2220STR \u03b1 RQP = 50\u00b0 (alternate angle)  In \u0394PQR  \u2220PRQ + \u2220RQP + \u2220RPQ = 180\u00b0 (sum of the angles in a triangle)  80\u00b0 + 50\u00b0 + \u2220RPQ = 180\u00b0  \u2220RPQ = 50\u00b0  \u2220RPQ + \u2220NPR = 180\u00b0 (sum of angles on a straight line)  50\u00b0 + \u2220NPR = 180\u00b0  \u2220NPR = 130\u00b0","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>37","subject":"Mathematics","year":"2017","type":"Objective","topic":"ALGEBRAIC PROCESSES : EXPANSION AND FACTORISATION","question":"Simplifytheexpressiona2b4-b2a4ab(a+b).","images":[],"options":{"A":"a2 - b2","B":"b2 - a2","C":"a2b - ab2","D":"ab2 - a2b"},"answer":"D","explanation":"a2b4 - b2a4ab(a + b)=a2b2(b2 - a2ab(a + b)  =-ab(a2-b2)(a+b)=-ab(a+b)(a-b)a+b= -ab(a - b)= -a2b + ab2= ab2 - a2b","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>38","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : SEQUENCE AND SERIES","question":"Findthe6thtermofthesequence:23,715,415,...","images":[],"options":{"A":"-1/3","B":"-1/5","C":"1/15","D":"1/5"},"answer":"A","explanation":"2/3 , 7/15 , 4/15 , -- - - ---   The sequence given is an arithmetic sequenc , since it has a common difference, d.  d=715-23  7-1015=-315=-15  Tn = a + (n - 1)d  T6 = a + 5d  =23+5(-15)  =23-1= -1/3","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>39","subject":"Mathematics","year":"2017","type":"Objective","topic":"MENSURATION : LENGTHS AND PERIMETERS","question":"The diagonal of a square is 60cm. Calculate its perimeter.","images":[],"options":{"A":"20&radic;2&nbsp;","B":"40&radic;2&nbsp;","C":"90&radic;2&nbsp;","D":"120&radic;2&nbsp;"},"answer":"D","explanation":"Apply pythagoras theorem:  2x2 = 3600  x2 = 1800  x = 30&radic;2&nbsp;cm  Perimeter = 4(x) = 4(30&radic;2&nbsp;) = 120&radic;2&nbsp;cm","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>40","subject":"Mathematics","year":"2017","type":"Objective","topic":"ALGEBRAIC PROCESSES : QUADRATIC EQUATIONS","question":"The roots of a quadratic equation are -1/2 and 2/3. Find the equation.","images":[],"options":{"A":"6x2 - x + 2 = 0","B":"6x2 - x - 2 = 0","C":"6x2 + x - 2 = 0","D":"6x2 + x + 2 = 0"},"answer":"B","explanation":"x=-12andx=23  (x+12)(x-23)=0  x2-2x3+x2-26=0  x2-x6-13=0  6x2 - x - 2 = 0","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>41","subject":"Mathematics","year":"2017","type":"Objective","topic":"ALGEBRAIC PROCESSES : CHANGE OF SUBJECT OF A FORMULA/RELATION","question":"Make x the subject of the relation  d=&radic;(6x-y2)&nbsp;","images":[],"options":{"A":"x=6d2+12y","B":"x=122d2 - y","C":"x=12y-2d2","D":"x=122d2 + y"},"answer":"D","explanation":"d=&radic;(6x-y2)&nbsp;  square both sides   d2=6x-y2  d2=12 - xy2x  2d2x = 12 - xy  x(2d2 + y) = 12  x=122d2 + y","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>42","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : LOGICAL REASONING","question":"Consider the statements: p: it is hot. q: it is raining. Which if the following symbols correctly represents the statement \"it is raining if and only if it is cold?","images":[],"options":{"A":"p \u21d4~q","B":"q \u21d4p","C":"~q \u21d4 ~q","D":"q \u21d4~p"},"answer":"D","explanation":"The statement \"it is raining if and only if it is cold\" can be represented in logical symbols as: q\u27fa\u223cp    This means that it is raining (q) is true if and only if it is cold (not hot, or ~p) is true.    Thus, the correct option is: q\u27fa\u223cp.","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>43","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : LAWS OF INDICES","question":"Given that t = 2-x, find 2x + 1 in terms of t.","images":[],"options":{"A":"2/t","B":"t/2","C":"t/2t","D":"2t"},"answer":"A","explanation":"t = 2-x  N:B: 2x-1) - (2-x)-1 and t-1 = (t)-1  t=12x  2x=1t  2x\u00d72  2x+1=2t","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>44","subject":"Mathematics","year":"2017","type":"Objective","topic":"PLANE GEOMETRY : ANGLES","question":"Find the value of m in the diagram.","images":["data:image/png;base64,"],"options":{"A":"72\u00b0","B":"68\u00b0","C":"44\u00b0","D":"34\u00b0"},"answer":"C","explanation":"NOTE: 2x = x + 68\u00b0 (external angles of a triangle   x = 68\u00b0  In the \u0394 given  m + 68\u00b0 + 68\u00b0 = 180\u00b0 (sum of a triangle)  m + 136\u00b0 = 180\u00b0  m = 44\u00b0","marks":"1","difficulty":"1"},{"id":"objective>Mathematics>2017>45","subject":"Mathematics","year":"2017","type":"Objective","topic":"STATISTICS AND PROBABILITY. : PROBABILITY","question":"Two bottles are drawn  with replacement  from a crate containing 8 coke, 12 fanta and 4 sprite bottles. What is the probability that the first is coke and the second is NOT coke?","images":[],"options":{"A":"1/12","B":"1/6","C":"2/9","D":"3/8"},"answer":"C","explanation":"Number of coke = 8  Number of Fanta = 12  Number of Sprite = 4  Total = 24  P(coke)=824=13  P(Notcoke)=1-13=23  P(cokeandnotcoke)=13\u00d723=29","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>46","subject":"Mathematics","year":"2017","type":"Objective","topic":"NUMBER AND NUMERATION : SIMPLE INTEREST AND COMPOUND INTEREST","question":"If the simple interest on a certain amount of money saved in a bank for 5 years at 2 1/2 % per annum is N500.00, calculate the total amount due after 6 years at the same rate.","images":[],"options":{"A":"N2,500.00","B":"N2,600.00","C":"N4,500.00","D":"N4,600.00"},"answer":"D","explanation":"I = \u20a6500  R = 2 1/2% = 5/2 %  T = 5 years  R = unknown  Recall:  I=PRT100  A = P + I  \u20a6500=P\u00d75\u00d7T2\u00d7100  500 \u00d7 200 = 5 \u00d7 P \u00d7 5  25P = 100,000  P = \u20a64,000  Now for 6 years   I=4000\u00d752\u00d76100  I=4\u00d75\u00d762=\u20a6600  The total amount = \u20a64,000 + \u20a6600= \u20a64,600","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>47","subject":"Mathematics","year":"2017","type":"Objective","topic":"STATISTICS AND PROBABILITY. : STATISTICS","question":"Calculate the variance of 2, 3, 3, 4, 5, 5, 5, 7, 7 and 1.","images":[],"options":{"A":"2.2","B":"3.4","C":"4.0","D":"4.2"},"answer":"D","explanation":"Given the set of numbers:  2, 3, 3, 4, 5, 5, 5, 7, 7, 9  x\u0305=2+3+3+4+5(3)+7(2)+910  =505=5  variance=(x-x\u0305)2n  Variance=9+4+4+1+0+0+4+4+1610= 42/10 = 4.2","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>48","subject":"Mathematics","year":"2017","type":"Objective","topic":"MENSURATION : AREAS","question":"A circular pond of radius 4m has a path of width 2.5m round it. Find, correct to two decimal places, the area of the path.  [Take \u03c0 = 22/7 ]","images":[],"options":{"A":"7.83m2","B":"32.29m2","C":"50.29m2","D":"82.50m2"},"answer":"D","explanation":"Total Area  = Area of Path + Area of pool  \u03c0(6.5)2 = Area of path + \u03c0(4)2  Area of path = \u03c0(6.5)2 - \u03c0(4)2= \u03c0(42.25-16)= \u03c0(26.25)cm2= 26.25\u03c0m2  =(26.25\u00d7227)m2= 82.5m2","marks":"1","difficulty":"3"},{"id":"objective>Mathematics>2017>49","subject":"Mathematics","year":"2017","type":"Objective","topic":"ALGEBRAIC PROCESSES : GRAPHS OF LINEAR AND QUADRATIC FUNCTIONS","question":"Thegraphofy=ax2+bx+cisshowninthediagram.Findtheminimumvaluey.","images":["data:image/png;base64,"],"options":{"A":"-2.0","B":"-2.1","C":"-2.3","D":"-2.5"},"answer":"D","explanation":"The minimum value of the quadratic graph is at y  = -2.5","marks":"1","difficulty":"2"},{"id":"objective>Mathematics>2017>50","subject":"Mathematics","year":"2017","type":"Objective","topic":"PLANE GEOMETRY : CIRCLES","question":"Inthediagram,RPisadiameterofcircleRSP,RPisproducedtoTandTSisatangenttothecircleasS. If \u2220 PRS = 24\u00b0, calculate the value of \u2220STR.","images":["data:image/png;base64,"],"options":{"A":"24\u00b0","B":"42\u00b0","C":"48\u00b0","D":"66\u00b0"},"answer":"B","explanation":"\u2220RSP = 90\u00b0 (angle in a semi-circle)  \u2220RPS = 180\u00b0 - (90\u00b0 + 24\u00b0)= 180\u00b0 - 114\u00b0 = 66\u00b0  \u2220RST = \u2220RPS = 66\u00b0 (angles in all segment)  x + y + z = 180\u00b0 (sum of *angles* in a triangle)  x = 180\u00b0 - (90\u00b0 + 66\u00b0)  x = 24\u00b0  y = 180\u00b0 - (66\u00b0) = 114\u00b0  24\u00b0 + 114\u00b0 + z = 180\u00b0  138\u00b0 + z = 180\u00b0  z = 42\u00b0","marks":"1","difficulty":"3"}];